import logging
from flask import Flask, request, jsonify
import os
import uuid

app = Flask(__name__)

# Set up logging configuration
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s [%(levelname)s] %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)

logger = logging.getLogger()

# Create a secure token for authentication
secret_key = os.urandom(24)
app.config['SECRET_KEY'] = secret_key

@app.before_request
def log_request():
    logger.info(f'Request from {request.remote_addr} - Method: {request.method}, URL: {request.path}')

@app.after_request
def log_response(response):
    logger.info(f'Response from {request.remote_addr} - Status Code: {response.status_code}')
    return response

@app.errorhandler(500)
def internal_server_error(e):
    logger.error(f'Internal Server Error - {e}')
    return jsonify({'error': 'Internal Server Error'}), 500

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data['username']
    password = data['password']

    # Log authentication attempt
    logger.info(f'Login Attempt - Username: {username}, Password: {password}')

    if username == 'admin' and password == 'password':
        token = str(uuid.uuid4())
        return jsonify({'token': token}), 200

    logger.error(f'Failed Login Attempt - Username: {username}, Password: {password}')
    return jsonify({'error': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)